CREATE TABLE background_jobs (id VARCHAR(36) NOT NULL, type ENUM('csv_import','csv_export') NOT NULL, status ENUM('queued','running','succeeded','failed','canceled') NOT NULL DEFAULT 'queued', model_id VARCHAR(36) NULL, payload JSON NOT NULL, progress TINYINT UNSIGNED NOT NULL DEFAULT 0, attempt TINYINT UNSIGNED NOT NULL DEFAULT 0, max_attempts TINYINT UNSIGNED NOT NULL DEFAULT 3, available_at DATETIME(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6), lease_token BINARY(32) NULL, lease_owner VARCHAR(128) NULL, lease_expires_at DATETIME(6) NULL, cancel_requested_at DATETIME(6) NULL, error_code VARCHAR(64) NULL, error_message VARCHAR(512) NULL, created_by VARCHAR(64) NOT NULL, created_at DATETIME(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6), started_at DATETIME(6) NULL, finished_at DATETIME(6) NULL, expires_at DATETIME(6) NULL, PRIMARY KEY (id), KEY idx_background_jobs_queued (status,available_at,id), KEY idx_background_jobs_leases (status,lease_expires_at,id), CONSTRAINT chk_background_jobs_progress CHECK (progress<=100), CONSTRAINT chk_background_jobs_attempts CHECK (attempt<=max_attempts AND max_attempts=3), CONSTRAINT chk_background_jobs_lease CHECK ((status='running' AND lease_token IS NOT NULL AND lease_owner IS NOT NULL AND lease_expires_at IS NOT NULL) OR (status<>'running' AND lease_token IS NULL AND lease_owner IS NULL AND lease_expires_at IS NULL))) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
